Event Start

	LoadWWPContext.Call(&Context)
	&EmpCod = &Context.EmpCod
	If &HTTPRequest.Method = HttpMethod.Get
		&SdtPagamentoDuplicata.FromXml(&Websession.Get('WWDuplicataCartao'))
	EndIf

	&FilCod = iif(&Context.FilCod.IsEmpty(),1,&Context.FilCod)
	&Hoje = serverdate()
	&IsStart = True

	Do 'VALIDASDT'
	&Mensagem.ForeColor = RGB(255,0,0)

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	&RcbCreTotInf.TooltipText = "Total Informado."
	&RcbCreTotDin.TooltipText = "Total em Dinheiro"
	&RcbCreVlrTot.TooltipText = "Valor Total á Receber"
	&RcbCreVlrRcb.TooltipText = "Total selecionado em duplicatas a receber."
	&MovDtaCon.TooltipText = "Data do recebimento da duplicata e crédito no caixa"
	&RcbCreVlrRcb.Visible = False
	&RcbCreVlrTot.Visible = False
	&RcbCreTotDin.Visible = False
	&RcbCreTotInf.Visible = False
	GridSdtPagamentoDuplicatas_Empowerer.GridInternalName = GridSdtPagamentoDuplicatas.InternalName
	GridSdtPagamentoDuplicatas.Rows = Page.Rows
	GridSdtPagamentoDuplicatasPaginationBar.RowsPerPageSelectedValue = GridSdtPagamentoDuplicatas.Rows

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event Refresh

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	&GridSdtPagamentoDuplicatasCurrentPage = GridSdtPagamentoDuplicatas.CurrentPage
	&GridSdtPagamentoDuplicatasPageCount = GridSdtPagamentoDuplicatas.PageCount

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event GridSdtPagamentoDuplicatas.Load

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	//this code should be inside the For Each used to load the grid
	&Deletar = !'<i class="fas fa-times"></i>'

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event GridSdtPagamentoDuplicatasPaginationBar.ChangePage

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	Do Case
		Case GridSdtPagamentoDuplicatasPaginationBar.SelectedPage = !'Previous'
			GridSdtPagamentoDuplicatas.PreviousPage()
		Case GridSdtPagamentoDuplicatasPaginationBar.SelectedPage = !'Next'
			&PageToGo = GridSdtPagamentoDuplicatas.CurrentPage
			&PageToGo += 1
			GridSdtPagamentoDuplicatas.GotoPage(&PageToGo)
		Otherwise
			&PageToGo.FromString(GridSdtPagamentoDuplicatasPaginationBar.SelectedPage)
			GridSdtPagamentoDuplicatas.GotoPage(&PageToGo)
	EndCase

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event GridSdtPagamentoDuplicatasPaginationBar.ChangeRowsPerPage

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	GridSdtPagamentoDuplicatas.Rows = GridSdtPagamentoDuplicatasPaginationBar.RowsPerPageSelectedValue
	GridSdtPagamentoDuplicatas.FirstPage()

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event 'DoConfirmar'

	&PadObs = DTOC(&MovDtaCon)
	PadraoUsuario.Call('G', 'WWDuplicataReceber', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)

	Do Case
		Case &RcbCreVlrTot > &RcbCreVlrRcb and &sdtPagamentoDuplicata.Count = 1
			DVelop_ConfirmPanel_Confirmar.ConfirmationText = 'ATENÇÃO!!! Confirma o recebimento com JUROS da(s) duplicata(s) selecionada(s)?'
		Case (&RcbCreVlrRcb = &RcbCreVlrTot)
			DVelop_ConfirmPanel_Confirmar.ConfirmationText = 'Confirma o recebimento da(s) Duplicata(s) a seguir?'
		Otherwise
		 	DVelop_ConfirmPanel_Confirmar.ConfirmationText = 'ATENÇÃO!!! Confirma o recebimento PARCIAL da(s) duplicata(s) selecionada(s)?'
	EndCase

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	DVelop_ConfirmPanel_Confirmar.Confirm()

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event DVelop_ConfirmPanel_Confirmar.Close

	&WebSession.Set('WWDuplicataCartao',&SdtPagamentoDuplicata.Toxml())

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	If DVelop_ConfirmPanel_Confirmar.Result = !'Yes'
		Do 'Do Action Confirmar'
	EndIf

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

