Event SdtPagamentoDuplicata__CrePlanCod.Click

	&PadObs = DTOC(&MovDtaCon)
	PadraoUsuario.Call('G', 'WWDuplicataReceber', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
	&WebSession.Set('WWDuplicataCartao',&SdtPagamentoDuplicata.Toxml())
	RecebimentoCartao.Call(&IsAuthorized,&MovDtaCon,&DeOndeVem)

EndEvent

Event &Deletar.Click

	&PadObs = DTOC(&MovDtaCon)
	PadraoUsuario.Call('G', 'WWDuplicataReceber', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
	&Index = 0					
	&Index = &SdtPagamentoDuplicata.IndexOf(&SdtPagamentoDuplicata.CurrentItem)
	&SdtPagamentoDuplicata.Remove(&Index)
	&WebSession.Set('WWDuplicataCartao',&SdtPagamentoDuplicata.Toxml())
	RecebimentoCartao.Call(&IsAuthorized,&MovDtaCon,&DeOndeVem)

EndEvent

Sub 'GravaFinanceiro'

	//GRAVA FINANCEIRO	
	If &RcbCreVlrTot > 0
	    GravaFinanceiroDuplicataCartao.Call(&EmpCod,&MovDtaCon,&RcbCreVlrTot,&IsDescontada,&SdtPagamentoDuplicata)
	EndIf

EndSub

Sub 'VALIDASDT'

	&IsErroPlanoConta = False
	&IsClienteDiferente = False
	&IsDescontada = False
//	&IsErroValeFun = False
	&index = 1
	&RcbCreVlrRcb = 0
	&CrePagVlrJur = 0
	&IsErroDuplicataSaldo = false

	&TotalBruto = 0
	&TotalTaxa = 0
	&TotalLiquido = 0

	For &sdtPagamentoDuplicataItem in &sdtPagamentoDuplicata
		&gridCreCliCod = &sdtPagamentoDuplicataItem.CreCliCod

		&TstCreCod = &sdtPagamentoDuplicataItem.CreCod
		&TstEmpCod = &sdtPagamentoDuplicataItem.EmpCod
		&TstFilCod = &sdtPagamentoDuplicataItem.FilCod

		Do 'TestaDuplicata'

		If &sdtPagamentoDuplicataItem.CreSts = 'D'
			&IsDescontada = True
		EndIf
		&AuxCreDupNro = &sdtPagamentoDuplicataItem.CreDupNro
		If &CreCliCod <> &gridCreCliCod and &index = 2
			&IsClienteDiferente = true
		EndIF
		&CreCliCod = &sdtPagamentoDuplicataItem.CreCliCod
		&index = 2
		If &IsClienteDiferente = true
			&MovItmCpl = 'CL: CLIENTES DIVERSOS'
		Else
			If &MovItmCpl = ''			
				&MovItmCpl = trim(&sdtPagamentoDuplicataItem.MovCpl)
			EndIf
		EndIf
		&RcbCreVlrRcb += &sdtPagamentoDuplicataItem.CreVlrPgt
		&CrePagVlrJur += &sdtPagamentoDuplicataItem.CrePagVlrJur

		&TotalBruto += &sdtPagamentoDuplicataItem.crevlrSdo
		&TotalTaxa += &sdtPagamentoDuplicataItem.crePagVlrTar //Taxa
		&TotalLiquido = &TotalBruto - &TotalTaxa

		&sdtPagamentoDuplicataItem.MovFunCod = 0

		If &sdtPagamentoDuplicataItem.CrePlanCod  = 0
			&IsErroPlanoConta = True
		EndIf
	EndFor

	If &IsStart = True
		If &RcbCreVlrTot.IsEmpty()
			&RcbCreVlrTot = &RcbCreVlrRcb + &CrePagVlrJur
		EndIF		
		If &IsDescontada = true
			&Mensagem = 'EXISTE(M) DUPLICATA(S) DESCONTADA(S), ELA(S) NÃO GERA(M) CRÉDITO(S) NO CAIXA!'
		EndIf
	EndIf

EndSub

Sub 'TestaDuplicata'

	For each Order EmpCod,FilCod,CreCod
		Where EmpCod = &TstEmpCod
		Where FilCod = &TstFilCod
		Where CreCod = &TstCreCod
		Where CreVlrSdo <= 0 
		&IsErroDuplicataSaldo = true
		msg('Atenção a duplicata número '+CreDupNro.Trim()+ ' e sequência '+trim(str(CreCod))+' Verifique!' )
		exit
	Endfor

EndSub
